function upsertRows(table, requestId, rows) {
  let writeIndex = 0;

  for (const row of table) {
    if (row.request_id !== requestId) {
      table[writeIndex] = row;
      writeIndex += 1;
    }
  }

  table.length = writeIndex;
  table.push(...rows);
}

